import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import MediaShowcaseSwiper from '../components/MediaShowcaseSwiper';
import { mediaItems } from '../mediaData/media';
import api from '../services/api';

const Home = () => {

  const [mediaItems, setMediaItems] = useState([]);

  useEffect(() => {
    const fetchMedia = async () => {
      try {
        const { data } = await api.get('/media');

        if (!data) return;

        const mappedItems = data?.media?.map((item) => ({
          id: item._id,
          type: item.type,
          src: `${api.defaults.baseURL}${item.url}`,
          thumb: `${api.defaults.baseURL}${item.url}`,
          alt: item.filename,
          label: new Date(item.createdAt).toLocaleDateString('en-GB', { month: 'short', year: 'numeric' }),
          caption: item.filename.replace(/\.[^/.]+$/, '').replace(/-/g, ' '),
        }))

        setMediaItems(mappedItems);
      } catch (error) {
        console.error('Error fetching media:', error);
      }
    };
    fetchMedia();
  }, []);

  return (
    <div>
      <section className="hero">
        <div className="hero-content">
          <h1>Redefining Luxury</h1>
          <p>Discover the essentials of modern minimalism.</p>
          <Link to="/shop" className="btn">Explore Collection</Link>
        </div>
      </section>

      <div className="container">
        <h2 className="page-title">Featured Pieces</h2>
        {mediaItems?.length > 0 ? <MediaShowcaseSwiper items={mediaItems} /> : <p>No media found</p>}
      </div>
    </div>
  );
};

export default Home;
